/**
 * Workflow Config Reader
 *
 * Reads `.ai/specs/workflow-config.yaml` (generated by /project-adapt)
 * to resolve project-specific build/test/lint commands.
 *
 * Makes the orchestrator project-agnostic — same code works for
 * AEM full-stack, AEM frontend modules, and standalone frontend projects.
 */

import { readFileSync, existsSync } from "fs";
import { resolve } from "path";

const CONFIG_FILENAME = ".ai/specs/workflow-config.yaml";

/**
 * Simple YAML parser for the workflow-config format.
 * Handles flat key-value pairs and nested objects (2 levels deep).
 * Does NOT handle arrays, multi-line strings, or complex YAML.
 * For those, use a real YAML library.
 */
function parseSimpleYaml(text) {
  const result = {};
  let currentSection = null;
  let currentSubSection = null;

  for (const raw of text.split("\n")) {
    const line = raw.replace(/\r$/, "");

    // Skip comments and empty lines
    if (/^\s*#/.test(line) || /^\s*$/.test(line)) continue;

    // Skip array items (modules, sourceRoots, etc.) — not needed for build commands
    if (/^\s*-\s/.test(line)) continue;

    const indent = line.search(/\S/);
    const content = line.trim();

    // Top-level section (no indent)
    if (indent === 0 && content.endsWith(":")) {
      currentSection = content.slice(0, -1);
      currentSubSection = null;
      if (!result[currentSection]) result[currentSection] = {};
      continue;
    }

    // Sub-section (2-space indent, ends with colon, no value)
    if (indent === 2 && content.endsWith(":") && !content.includes(": ")) {
      currentSubSection = content.slice(0, -1);
      if (currentSection && typeof result[currentSection] === "object") {
        result[currentSection][currentSubSection] = {};
      }
      continue;
    }

    // Key-value pair
    const kvMatch = content.match(/^(\w[\w-]*):\s*(.+)$/);
    if (kvMatch) {
      const [, key, rawValue] = kvMatch;
      // Strip quotes
      const value = rawValue.replace(/^["']|["']$/g, "");

      if (indent >= 4 && currentSection && currentSubSection) {
        // Nested value (e.g., build.full)
        if (typeof result[currentSection] !== "object") result[currentSection] = {};
        if (typeof result[currentSection][currentSubSection] !== "object") {
          result[currentSection][currentSubSection] = {};
        }
        result[currentSection][currentSubSection][key] = value;
      } else if (indent >= 2 && currentSection) {
        // Section value (e.g., project.name)
        if (typeof result[currentSection] !== "object") result[currentSection] = {};
        result[currentSection][key] = value;
      } else {
        result[key] = value;
      }
    }
  }

  return result;
}

/**
 * Load workflow config from the project root.
 *
 * @param {string} [projectRoot] - Project root directory. Defaults to cwd.
 * @returns {{ build: object, project: object, conventions: object, projectManagement: object, aem?: object } | null}
 */
export function loadWorkflowConfig(projectRoot) {
  const root = projectRoot || process.cwd();
  const configPath = resolve(root, CONFIG_FILENAME);

  if (!existsSync(configPath)) {
    console.warn(`[WorkflowConfig] Not found: ${configPath}`);
    return null;
  }

  try {
    const text = readFileSync(configPath, "utf8");
    const parsed = parseSimpleYaml(text);
    console.log(`[WorkflowConfig] Loaded from ${configPath}`);
    return parsed;
  } catch (err) {
    console.warn(`[WorkflowConfig] Failed to parse: ${err.message}`);
    return null;
  }
}

/**
 * Get build commands from workflow config.
 * Returns an object with build.full, build.test, build.compile, build.lint, build.deploy.
 *
 * @param {string} [projectRoot] - Project root directory.
 * @returns {{ full: string, test: string, compile: string, lint: string, deploy: string, testSingle: string }}
 */
export function getBuildCommands(projectRoot) {
  const config = loadWorkflowConfig(projectRoot);
  const build = config?.build || {};

  return {
    full: build.full || "mvn clean install",
    test: build.test || "mvn test",
    compile: build.compile || "",
    lint: build.lint || "",
    deploy: build.deploy || "",
    testSingle: build.testSingle || "",
  };
}

/**
 * Get the self-check command sequence for the Dev Agent.
 * Returns an ordered array of { label, command } entries.
 * Skips empty commands (e.g., no lint for some projects).
 *
 * @param {string} [projectRoot] - Project root directory.
 * @returns {Array<{ label: string, command: string }>}
 */
export function getSelfCheckSteps(projectRoot) {
  const cmds = getBuildCommands(projectRoot);

  const steps = [
    { label: "compilation", command: cmds.full },
    { label: "unitTests", command: cmds.test },
  ];

  if (cmds.compile) {
    steps.push({ label: "frontendBuild", command: cmds.compile });
  }
  if (cmds.lint) {
    steps.push({ label: "lint", command: cmds.lint });
  }

  return steps.filter((s) => s.command);
}

/**
 * Get project metadata from workflow config.
 *
 * @param {string} [projectRoot] - Project root directory.
 * @returns {{ name: string, type: string, baseBranch: string, adoProject: string, adoRepo: string } | null}
 */
export function getProjectMeta(projectRoot) {
  const config = loadWorkflowConfig(projectRoot);
  if (!config) return null;

  return {
    name: config.project?.name || "",
    type: config.project?.type || "",
    baseBranch: config.conventions?.baseBranch || "develop",
    branchPrefix: config.conventions?.branchPrefix || "feature",
    adoOrg: config.projectManagement?.organization ,
    adoProject: config.projectManagement?.project || "",
    adoRepo: config.projectManagement?.repository || "",
  };
}
